@page "/catalog"
@using sv_3e8bc36bc98949fd8d94b9bd1a97a400.Services
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<div class="catalog-container">
    <!-- Left Sidebar: Filters -->
    <aside class="catalog-sidebar">
        <h3>Filters</h3>

        <div class="filter-section">
            <h4>Category</h4>
            @if (categories is not null)
            {
                @foreach (var category in categories)
                {
                    <label class="filter-checkbox">
                        <input type="checkbox"
                               checked="@(selectedCategories.Contains(category))"
                               @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                        @category
                    </label>
                }
            }
            else if (!hasError)
            {
                <p class="text-muted">Loading categories…</p>
            }
        </div>

        <div class="filter-section">
            <h4>Price Range</h4>
            <div class="price-inputs">
                <label>
                    Min
                    <input type="number" min="0" step="0.01"
                           @bind="minPrice" placeholder="Min" />
                </label>
                <label>
                    Max
                    <input type="number" min="0" step="0.01"
                           @bind="maxPrice" placeholder="Max" />
                </label>
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
        </div>

        <div class="filter-actions">
            <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
            <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
        </div>
    </aside>

    <!-- Main Content -->
    <main class="catalog-main">
        @if (hasError)
        {
            <div class="catalog-error">
                <p>Something went wrong while loading products. Please try again.</p>
                <button class="btn-apply" @onclick="ApplyFilters">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <div class="catalog-loading">
                <p>Loading products…</p>
            </div>
        }
        else if (searchResult is null || searchResult.Items.Count == 0)
        {
            <div class="catalog-empty">
                <p>No products found matching your criteria.</p>
                <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
            </div>
        }
        else
        {
            <!-- Toolbar -->
            <div class="catalog-toolbar">
                <div class="toolbar-sort">
                    <label for="sort-select">Sort by:</label>
                    <select id="sort-select" @bind="currentSort" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="toolbar-info">
                    Showing @rangeStart–@rangeEnd of @searchResult.TotalCount products
                </span>
            </div>

            <!-- Product Grid -->
            <div class="product-grid">
                @foreach (var product in searchResult.Items)
                {
                    <ProductCard Product="product"
                                 OnProductSelected="HandleProductSelected"
                                 OnAddToCart="HandleAddToCart" />
                }
            </div>

            <!-- Pagination -->
            <nav class="catalog-pagination">
                <button class="page-btn"
                        disabled="@(currentPage <= 1)"
                        @onclick="() => GoToPage(currentPage - 1)">
                    Previous
                </button>

                @for (int i = 1; i <= totalPages; i++)
                {
                    var pageNum = i;
                    <button class="page-btn @(pageNum == currentPage ? "active" : "")"
                            @onclick="() => GoToPage(pageNum)">
                        @pageNum
                    </button>
                }

                <button class="page-btn"
                        disabled="@(currentPage >= totalPages)"
                        @onclick="() => GoToPage(currentPage + 1)">
                    Next
                </button>
            </nav>
        }
    </main>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? searchResult;
    private bool isLoading = true;
    private bool hasError;

    private int totalPages => searchResult is null || searchResult.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)searchResult.TotalCount / PageSize);

    private int rangeStart => searchResult is null ? 0 : (searchResult.Page - 1) * searchResult.PageSize + 1;
    private int rangeEnd => searchResult is null ? 0 : Math.Min(searchResult.Page * searchResult.PageSize, searchResult.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAndProducts();
    }

    private async Task LoadCategoriesAndProducts()
    {
        isLoading = true;
        hasError = false;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = SearchProducts();

            categories = await categoriesTask;
            await productsTask;
        }
        catch
        {
            hasError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );

        searchResult = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        isLoading = true;
        hasError = false;

        try
        {
            await SearchProducts();
        }
        catch
        {
            hasError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentSort = "price_asc";
        currentPage = 1;

        await ApplyFilters();
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await ApplyFilters();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;

        isLoading = true;
        hasError = false;

        try
        {
            await SearchProducts();
        }
        catch
        {
            hasError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

