toolArgs.file_text:
.catalog-container {
    display: flex;
    gap: 24px;
    max-width: 1280px;
    margin: 0 auto;
    padding: 24px 16px;
}

/* Sidebar */
.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
    background: #f9f9fb;
    border-radius: 8px;
    padding: 20px;
    align-self: flex-start;
    position: sticky;
    top: 24px;
}

.catalog-sidebar h3 {
    margin: 0 0 16px;
    font-size: 1.2rem;
    color: #333;
}

.filter-section {
    margin-bottom: 20px;
}

.filter-section h4 {
    margin: 0 0 8px;
    font-size: 0.9rem;
    color: #555;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.filter-checkbox {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 4px 0;
    cursor: pointer;
    font-size: 0.95rem;
}

.filter-checkbox input[type="checkbox"] {
    width: 16px;
    height: 16px;
    cursor: pointer;
}

.price-inputs {
    display: flex;
    gap: 12px;
}

.price-inputs label {
    display: flex;
    flex-direction: column;
    font-size: 0.85rem;
    color: #666;
    flex: 1;
}

.price-inputs input {
    margin-top: 4px;
    padding: 6px 8px;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
    width: 100%;
    box-sizing: border-box;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.btn-apply {
    padding: 10px 16px;
    border: none;
    border-radius: 6px;
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.2s;
}

.btn-apply:hover {
    background: #0b5ed7;
}

.btn-clear {
    padding: 10px 16px;
    border: 1px solid #ccc;
    border-radius: 6px;
    background: #fff;
    color: #333;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.2s;
}

.btn-clear:hover {
    background: #f0f0f0;
}

/* Main content */
.catalog-main {
    flex: 1;
    min-width: 0;
}

/* Toolbar */
.catalog-toolbar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 12px;
    padding: 12px 16px;
    background: #f9f9fb;
    border-radius: 8px;
    margin-bottom: 20px;
}

.toolbar-sort {
    display: flex;
    align-items: center;
    gap: 8px;
}

.toolbar-sort label {
    font-size: 0.9rem;
    color: #555;
    white-space: nowrap;
}

.toolbar-sort select {
    padding: 6px 10px;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
    background: #fff;
}

.toolbar-info {
    font-size: 0.9rem;
    color: #666;
}

/* Product Grid */
.product-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 20px;
}

/* Pagination */
.catalog-pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 6px;
    margin-top: 28px;
    flex-wrap: wrap;
}

.page-btn {
    padding: 8px 14px;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #e9ecef;
}

.page-btn.active {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.page-btn:disabled {
    color: #adb5bd;
    cursor: not-allowed;
    background: #f8f9fa;
}

/* State messages */
.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 60px 20px;
    color: #666;
}

.catalog-error {
    color: #dc3545;
}

.catalog-error .btn-apply {
    margin-top: 12px;
}

.catalog-empty .btn-clear {
    margin-top: 12px;
}

.text-muted {
    color: #999;
    font-size: 0.9rem;
}

